import "../styles/navbar.css";

function Navbar() {
  return (
    <nav className="navbar">

      <h2 className="logo">Harshini</h2>

      <ul className="nav-links">
        <li>Home</li>
        <li>About</li>
        <li>Skills</li>
        <li>Projects</li>
        <li>Contact</li>
      </ul>

    </nav>
  );
}

export default Navbar;
